-- ============================================================================
-- GUNDI ENGROS AS -- Real product catalog import
-- Generated from products-936094414 MVA-2025-12-03.csv and
-- products-936094414 MVA-2026-02-15.csv
--
-- Run this in: Supabase Dashboard -> SQL Editor -> New query -> Run
-- Safe to re-run: categories upsert by slug, products upsert by sku.
-- ============================================================================

-- ---------------------------------------------------------------------------
-- 1. Replace the placeholder categories with the real business categories
-- ---------------------------------------------------------------------------
delete from public.categories
  where slug in ('mel-og-bakevarer', 'olje-og-fett', 'emballasje', 'kjottprodukter', 'meieri')
  and not exists (select 1 from public.products where products.category_id = categories.id);

on conflict (slug) do update set name = excluded.name, sort_order = excluded.sort_order;

-- ---------------------------------------------------------------------------
-- 2. Products (360 unique items across both price lists)
-- ---------------------------------------------------------------------------
on conflict (sku) do update set
  name = excluded.name,
  category_id = excluded.category_id,
  unit = excluded.unit,
  price_ex_vat = excluded.price_ex_vat,
  vat_rate = excluded.vat_rate;
